// In JavaScript this would silently concatenate instead of add
// TypeScript catches the mistake at compile time

function calculateBonus(salary: number, rate: number): number {
  return salary * rate;
}

const annualSalary = 85000;
const bonusRate = 0.1;

console.log(`Bonus: $${calculateBonus(annualSalary, bonusRate)}`);
console.log(`Total: $${annualSalary + calculateBonus(annualSalary, bonusRate)}`);

