// TypeScript infers all types from the initial values
const productName = "TypeScript Handbook";   // inferred: string
const price = 29.99;                          // inferred: number
const inStock = true;                         // inferred: boolean

// This would be a compile error — TypeScript caught it:
// price = "free";  // ← Type 'string' is not assignable to type 'number'

const discounted = price * 0.8;
console.log(`${productName}: $${discounted.toFixed(2)}`);
console.log(`Available: ${inStock}`);

function createGreeting(
  name: string,
  role: string,
  age: number
): string {
  return `Welcome back, ${name}! You're logged in as ${role} (age ${age}).`;
}

function calculateYearsUntilRetirement(currentAge: number, retirementAge: number): number {
  return retirementAge - currentAge;
}

console.log(createGreeting("Alice", "admin", 34));
console.log(createGreeting("Bob", "editor", 28));
console.log(`Years until retirement: ${calculateYearsUntilRetirement(34, 65)}`);

function parseUserAge(input: string): number {
  const age = parseInt(input, 10);
  if (isNaN(age)) {
    throw new Error(`"${input}" is not a valid age`);
  }
  if (age < 0 || age > 150) {
    throw new Error(`Age ${age} is out of range`);
  }
  return age;
}

const testInputs = ["25", "abc", "-5", "42"];

for (const input of testInputs) {
  try {
    const age = parseUserAge(input);
    console.log(`Valid age: ${age}`);
  } catch (error) {
    // error is `unknown` — must narrow before accessing .message
    if (error instanceof Error) {
      console.log(`Error: ${error.message}`);
    }
  }
}
